-- ============================================================
-- VISTAS PARA POWER BI
-- ============================================================

CREATE OR REPLACE VIEW vw_postulaciones_gestion AS
SELECT p.id_postulacion, p.numero_postulacion, p.codigo, p.fecha,
    YEAR(p.fecha) AS anio, MONTH(p.fecha) AS mes, p.presupuesto_total,
    i.nombre AS iniciativa, ti.nombre AS tipo_iniciativa,
    e.id_empresa, e.nombre AS empresa, e.rut AS rut_empresa,
    e.convenio_marco, te.nombre AS tamano_empresa,
    s.nombre AS sede, re.nombre AS region_ejecucion,
    ri.nombre AS region_impacto, ep.nombre AS estado
FROM postulacion p
JOIN iniciativa i ON p.id_iniciativa=i.id_iniciativa
JOIN tipo_iniciativa ti ON p.id_tipo_iniciativa=ti.id_tipo
JOIN empresa e ON p.id_empresa=e.id_empresa
JOIN tamano_empresa te ON e.id_tamano=te.id_tamano
JOIN sede s ON p.id_sede=s.id_sede
JOIN region re ON p.id_region_ejecucion=re.id_region
JOIN region ri ON p.id_region_impacto=ri.id_region
JOIN estado_postulacion ep ON p.id_estado=ep.id_estado;

CREATE OR REPLACE VIEW vw_equipo_gestion AS
SELECT pp.id_postulacion, p2.codigo, p2.fecha,
    YEAR(p2.fecha) AS anio, MONTH(p2.fecha) AS mes,
    per.nombre AS nombre_persona, per.rut AS rut_persona,
    tp.nombre AS tipo_integrante, pp.rol, pp.departamento_area,
    s.nombre AS sede_integrante, re.nombre AS region_ejecucion,
    e.nombre AS empresa, e.convenio_marco, te.nombre AS tamano_empresa
FROM postulacion_persona pp
JOIN postulacion p2 ON pp.id_postulacion=p2.id_postulacion
JOIN persona per ON pp.id_persona=per.id_persona
JOIN tipo_persona tp ON pp.id_tipo_persona=tp.id_tipo_persona
JOIN sede s ON pp.id_sede=s.id_sede
JOIN empresa e ON p2.id_empresa=e.id_empresa
JOIN tamano_empresa te ON e.id_tamano=te.id_tamano
JOIN region re ON p2.id_region_ejecucion=re.id_region;

