USE ct_usm_postulaciones;

-- ============================================================
-- FIX emails postulacion_persona (personas T2, ids 1-26)
-- Cada persona queda con un único email canónico en todos sus posts
-- ============================================================

UPDATE postulacion_persona SET email = 'jperez@usm.cl' WHERE id_postulacion = 1 AND id_persona = 1;
